mapper.select:
SELECT id, username, password_hash, nickname, role, status, failed_login_attempts, lock_expired_at, last_login_at, created_at, updated_at, created_by, updated_by, deleted, version FROM user WHERE deleted = 0
AND username LIKE CONCAT('%', #{username}, '%')
AND role = #{role}
AND status = #{status}
ORDER BY created_at DESC
